class Solution(object):
    def countMentions(self, numberOfUsers, events):
        # Sort by timestamp; OFFLINE before MESSAGE at same timestamp
        events.sort(key=lambda e: (int(e[1]), 0 if e[0] == 'OFFLINE' else 1))
        mentions = [0] * numberOfUsers
        offline_until = {}  # user_id -> time they come back online
        for event in events:
            t = int(event[1])
            if event[0] == 'OFFLINE':
                uid = int(event[2])
                offline_until[uid] = t + 60
            else:  # MESSAGE
                msg = event[2]
                if msg == 'ALL':
                    for i in range(numberOfUsers):
                        mentions[i] += 1
                elif msg == 'HERE':
                    for i in range(numberOfUsers):
                        if offline_until.get(i, 0) <= t:
                            mentions[i] += 1
                else:
                    for token in msg.split():
                        uid = int(token[2:])
                        mentions[uid] += 1
        return mentions
